from dataclasses import dataclass

@dataclass
class AIFeatureMargin:
    """Contribution margin model for a single AI-powered feature."""
    # Revenue
    monthly_active_users_with_ai: int
    avg_revenue_per_user_usd: float
    ai_feature_revenue_attribution_pct: float  # % of revenue credited to AI feature

    # Incremental AI costs
    monthly_token_cost_usd: float
    monthly_ai_infra_overhead_usd: float      # additional infra for AI gateway, logging
    monthly_ai_support_cost_usd: float        # AI-specific support tickets

    @property
    def attributed_revenue(self) -> float:
        return (self.monthly_active_users_with_ai
                * self.avg_revenue_per_user_usd
                * self.ai_feature_revenue_attribution_pct)

    @property
    def total_ai_incremental_cost(self) -> float:
        return (self.monthly_token_cost_usd
                + self.monthly_ai_infra_overhead_usd
                + self.monthly_ai_support_cost_usd)

    @property
    def contribution_margin_usd(self) -> float:
        return self.attributed_revenue - self.total_ai_incremental_cost

    @property
    def contribution_margin_pct(self) -> float:
        if self.attributed_revenue == 0:
            return 0.0
        return self.contribution_margin_usd / self.attributed_revenue * 100

    @property
    def ai_cost_as_pct_of_attributed_revenue(self) -> float:
        return self.monthly_token_cost_usd / self.attributed_revenue * 100

    def summary(self) -> dict:
        return {
            "attributed_revenue_usd": round(self.attributed_revenue, 2),
            "total_ai_cost_usd": round(self.total_ai_incremental_cost, 2),
            "contribution_margin_usd": round(self.contribution_margin_usd, 2),
            "contribution_margin_pct": round(self.contribution_margin_pct, 1),
            "ai_token_pct_of_revenue": round(self.ai_cost_as_pct_of_attributed_revenue, 1),
        }

# Example
feature = AIFeatureMargin(
    monthly_active_users_with_ai=5_000,
    avg_revenue_per_user_usd=49.0,
    ai_feature_revenue_attribution_pct=0.20,   # 20% of revenue attributed to AI feature
    monthly_token_cost_usd=8_500,
    monthly_ai_infra_overhead_usd=1_200,
    monthly_ai_support_cost_usd=400,
)
print(feature.summary())
# attributed_revenue: $49,000; total_ai_cost: $10,100; margin: $38,900 (79.4%)
# ai_token_pct_of_revenue: 17.3%

from dataclasses import dataclass
from typing import List

@dataclass
class ModelTierOption:
    model_name: str
    cost_per_conversation_usd: float
    quality_score: float          # 0.0–1.0 from evals suite
    monthly_conversations_per_user: float

    def monthly_cost_per_user(self) -> float:
        return self.cost_per_conversation_usd * self.monthly_conversations_per_user

def margin_sensitivity(
    attributed_revenue_per_user: float,
    model_options: List[ModelTierOption],
) -> list:
    rows = []
    for opt in model_options:
        ai_cost = opt.monthly_cost_per_user()
        ai_pct = ai_cost / attributed_revenue_per_user * 100
        gross_margin_pct = (1 - ai_cost / attributed_revenue_per_user) * 100
        rows.append({
            "model": opt.model_name,
            "monthly_ai_cost_per_user": round(ai_cost, 3),
            "ai_pct_of_revenue": round(ai_pct, 1),
            "gross_margin_pct": round(gross_margin_pct, 1),
            "quality_score": opt.quality_score,
        })
    return sorted(rows, key=lambda x: x["gross_margin_pct"], reverse=True)

options = [
    ModelTierOption("claude-haiku-4",    0.002, 0.78, 20),
    ModelTierOption("claude-sonnet-4",   0.008, 0.91, 20),
    ModelTierOption("claude-opus-4",     0.030, 0.97, 20),
]

for row in margin_sensitivity(10.0, options):
    print(row)

from dataclasses import dataclass
from typing import Dict
import datetime

@dataclass
class FeatureMarginSnapshot:
    feature_id: str
    period: str           # "2026-07"
    attributed_revenue_usd: float
    token_cost_usd: float
    infra_overhead_usd: float
    support_cost_usd: float

    @property
    def total_ai_cost(self) -> float:
        return self.token_cost_usd + self.infra_overhead_usd + self.support_cost_usd

    @property
    def contribution_margin_usd(self) -> float:
        return self.attributed_revenue_usd - self.total_ai_cost

    @property
    def contribution_margin_pct(self) -> float:
        if self.attributed_revenue_usd == 0:
            return 0.0
        return self.contribution_margin_usd / self.attributed_revenue_usd * 100

    @property
    def is_margin_healthy(self) -> bool:
        return self.contribution_margin_pct >= 60.0  # 60% target

class FeatureMarginLedger:
    def __init__(self):
        self._records: Dict[str, list] = {}

    def record(self, snapshot: FeatureMarginSnapshot) -> None:
        key = snapshot.feature_id
        if key not in self._records:
            self._records[key] = []
        self._records[key].append(snapshot)

    def current_margin(self, feature_id: str) -> float:
        records = self._records.get(feature_id, [])
        if not records:
            return 0.0
        return records[-1].contribution_margin_pct

    def trend(self, feature_id: str, months: int = 3) -> list:
        return [r.contribution_margin_pct for r in self._records.get(feature_id, [])[-months:]]
